import{_ as o,o as t,c,ag as d}from"./chunks/framework.D4O_uTxf.js";const m=JSON.parse('{"title":"Build & Test","description":"","frontmatter":{},"headers":[],"relativePath":"upstream-governance/zen-mcp-server/fragemented/AGENTS.md","filePath":"upstream-governance/zen-mcp-server/fragemented/AGENTS.md","lastUpdated":1771844172000}'),i={name:"upstream-governance/zen-mcp-server/fragemented/AGENTS.md"};function r(a,e,s,n,l,p){return t(),c("div",null,[...e[0]||(e[0]=[d('<h1 id="build-test" tabindex="-1">Build &amp; Test <a class="header-anchor" href="#build-test" aria-label="Permalink to &quot;Build &amp; Test&quot;">​</a></h1><ul><li>Install: <code>pip install -e .[dev]</code> (requires Python 3.12+; use the repo <code>.python-version</code>).</li><li>Unit tests: <code>python -m pytest -xvs</code>.</li><li>Targeted test: <code>python -m pytest tests/&lt;path&gt;::&lt;TestClass&gt;::&lt;test_name&gt; -xvs</code>.</li><li>Simulator suite: <code>python communication_simulator_test.py --verbose</code>.</li><li>Lint &amp; format: <code>ruff check .</code>, <code>black --check .</code>, <code>isort --check-only .</code>.</li><li>Auto-fix style: <code>ruff check . --fix</code>, <code>black .</code>, <code>isort .</code>.</li><li>Logs tailing while tests run: <code>tail -f logs/mcp_server.log</code> or <code>tail -f logs/mcp_activity.log</code>.</li></ul><p>Always run unit tests plus <code>ruff check .</code> before committing. Run the simulator suite when touching protocol, provider, or streaming code.</p><h1 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h1><ul><li><code>api/</code>: FastAPI HTTP surface (MCP-compatible JSON-RPC bridge, auth guards, health probes).</li><li><code>server/</code> &amp; <code>services/</code>: Core orchestration, streaming manager, task execution, and provider wiring.</li><li><code>providers/</code>: Model/client adapters; follow hexagonal ports/adapters. Keep credentials outside repo.</li><li><code>tools/</code>: MCP tool implementations (Read, Execute, Planner, etc.) used by both CLI and automation.</li><li><code>work-prompts/</code>: Canonical prompt sheets and templates that drive architecture, planning, and QA reviews.</li><li><code>docs/</code>: Canonical blueprints, plans, and agent guides (<code>docs/misc_top_level/AGENTS.md</code>, <code>docs/dev-agents/</code>, <code>docs/plans/</code>).</li><li><code>tests/</code>, <code>smoke/</code>, <code>qa_data/</code>: Pytest suites, smoke harnesses, and fixtures. Respect layering—unit tests stay near subject.</li></ul><p>Guardrails: maintain ports/adapters separation, keep provider logic out of domain services, persist environment secrets via <code>.env*</code>.</p><h1 id="agent-tooling-shortcuts" tabindex="-1">Agent Tooling &amp; Shortcuts <a class="header-anchor" href="#agent-tooling-shortcuts" aria-label="Permalink to &quot;Agent Tooling &amp; Shortcuts&quot;">​</a></h1><p>This repository runs a 100% agent-driven lifecycle: humans provide intent or feedback, and droids handle research → planning → development → refinement → review → QA → deployment → evaluation. Keep requests scoped and trigger the right subagents so the pipeline stays autonomous.</p><p>Custom droids live in <code>.factory/droids/</code> (project overrides) and <code>.factory/personal/</code> (copy to <code>~/.factory/droids/</code> if desired):</p><ul><li><code>code-reviewer</code>, <code>blueprint-curator</code>, <code>test-strategist</code>, <code>security-auditor</code>, <code>plan-orchestrator</code>, <code>ops-concierge</code>.</li></ul><p>Custom slash commands are in <code>.factory/commands/</code>. Highlights:</p><ul><li><strong>Reviews &amp; Quality</strong>: <code>/code-review</code>, <code>/quality-gate</code>, <code>/test-strategy</code>, <code>/simulator-suite</code>.</li><li><strong>Docs &amp; Planning</strong>: <code>/doc-sync</code>, <code>/planning-brief</code>, <code>/workprompt-index</code>, <code>/agent-briefing</code>, <code>/wbs-pert</code>.</li><li><strong>Security &amp; Ops</strong>: <code>/security-sweep</code>, <code>/provider-audit</code>, <code>/log-triage</code>, <code>/ops-handoff</code>, <code>/release-checklist</code>, <code>/housekeeping</code>.</li><li><strong>Platform Enablement</strong>: <code>/dev-setup</code>, <code>/migration-scout</code>, <code>/dependency-scan</code>, <code>/warp-ops</code>, <code>/standup</code>.</li></ul><p>Parallel delegations are encouraged: let <code>plan-orchestrator</code> build WBS/PERT while <code>test-strategist</code> fleshes out coverage and <code>ops-concierge</code> clears housekeeping, then feed their outputs into <code>/quality-gate</code> or <code>/release-checklist</code>.</p><p>Use <code>/commands</code> → <strong>Reload (R)</strong> after editing. Commands reference the work prompts and blueprints above.</p><h1 id="git-workflow-evidence" tabindex="-1">Git Workflow &amp; Evidence <a class="header-anchor" href="#git-workflow-evidence" aria-label="Permalink to &quot;Git Workflow &amp; Evidence&quot;">​</a></h1><ul><li>Branch naming: <code>feature/&lt;slug&gt;</code>, <code>fix/&lt;slug&gt;</code>, <code>chore/&lt;slug&gt;</code>.</li><li>Keep commits atomic; prefer <code>feat:</code>, <code>fix:</code>, <code>test:</code>, <code>docs:</code>, <code>chore:</code>.</li><li>Mandatory proof before merge: <ul><li><code>python -m pytest -xvs</code></li><li><code>ruff check .</code></li><li>Evidence: log excerpt, screenshot, or simulator output when relevant.</li><li>Update blueprints/work-prompts when architecture or process changes occur.</li></ul></li></ul><p>Use <code>/release-checklist</code> before tagging, <code>/incident-postmortem</code> after outages, and <code>/doc-sync</code> whenever docs drift.</p><h1 id="security-ops-notes" tabindex="-1">Security &amp; Ops Notes <a class="header-anchor" href="#security-ops-notes" aria-label="Permalink to &quot;Security &amp; Ops Notes&quot;">​</a></h1><ul><li>Secrets live in <code>.env*</code> (never commit). Auth modules under <code>auth/</code> and <code>conf/</code> expect environment configuration.</li><li>Network/tool execution is sandboxed; expand permissions via <code>.codex/permissions.local.toml</code>, <code>.claude/settings.local.json</code>, <code>.auggie/settings.local.json</code>.</li><li>When changing provider integrations or auth flows, run <code>/security-sweep</code> and coordinate with <code>docs/reports/</code> owners.</li><li>Logs rotate at 20 MB; use <code>logs/mcp_server.log</code> and <code>logs/mcp_activity.log</code> for debugging. Simulator tests require <code>LOG_LEVEL=DEBUG</code>.</li><li>Use <code>/housekeeping &lt;scope&gt;</code> (via <code>ops-concierge</code>) for simple chores so dev droids stay focused on feature work.</li></ul><h1 id="documentation-prompts" tabindex="-1">Documentation &amp; Prompts <a class="header-anchor" href="#documentation-prompts" aria-label="Permalink to &quot;Documentation &amp; Prompts&quot;">​</a></h1><ul><li>Architecture source of truth: <code>ARCHITECTURE_BLUEPRINT.md</code>.</li><li>Delivery planning: <code>DELIVERY_BLUEPRINT.md</code>, <code>docs/plans/</code>.</li><li>Prompt canon: <code>work-prompts/</code> with quick index via <code>/workprompt-index</code>.</li><li>Agent guides: <code>docs/dev-agents/CLAUDE.md</code>, <code>docs/dev-agents/claude-code-sdk.md</code>, <code>docs/misc_top_level/AGENTS.md</code>.</li><li>Update docs alongside code; <code>/doc-sync</code> and <code>blueprint-curator</code> help enumerate edits.</li></ul><h1 id="validation-checklist-before-merge" tabindex="-1">Validation Checklist Before Merge <a class="header-anchor" href="#validation-checklist-before-merge" aria-label="Permalink to &quot;Validation Checklist Before Merge&quot;">​</a></h1><ul><li>✅ Code change reviewed by <code>code-reviewer</code> droid or <code>/code-review</code>.</li><li>✅ Tests &amp; lint commands executed with passing output attached to PR.</li><li>✅ Documentation updates identified via <code>/doc-sync</code>.</li><li>✅ Security review performed (<code>/security-sweep</code>) for auth/provider changes.</li><li>✅ Release implications captured via <code>/release-checklist</code> when applicable.</li></ul><p>Agents should read this briefing plus the relevant work prompt before planning any change.</p>',24)])])}const h=o(i,[["render",r]]);export{m as __pageData,h as default};
